pub async fn delete(context: &Context, contact_id: ContactId) -> Result<()> {
    if contact_id.is_special() {
        return Ok(());
    }

    context.inner.sql.transaction(|transaction| {
        // Check if the contact is used in any chats
        let count: i64 = transaction.query_row(
            "SELECT COUNT(*) FROM chats_contacts WHERE contact_id=?",
            [contact_id],
            |row| row.get(0),
        )?;
        if count >= 1 {
            return Ok(());
        }

        // Check if the contact is used in any messages
        let count: i64 = transaction.query_row(
            "SELECT COUNT(*) FROM msgs WHERE from_id=? OR to_id=?",
            params_iter![contact_id, contact_id],
            |row| row.get(0),
        )?;
        if count >= 1 {
            return Ok(());
        }

        // Delete the contact
        transaction.execute("DELETE FROM contacts WHERE id=?", [contact_id])?;

        Ok(())
    })
    .await?;

    context.inner.emit_event(EventType::ContactsChanged(None));

    Ok(())
}

