    } else if qr.starts_with(DCACCOUNT_SCHEME) {
        decode_account(qr)
    } else if qr.starts_with(DCWEBRTC_SCHEME) {
        decode_webrtc_instance(context, qr)
    } else if qr.starts_with(DCBACKUP_SCHEME) {
        decode_backup(qr)
    } else if qr.starts_with(IDELTACHAT_SCHEME) {
        decode_ideltachat(context, IDELTACHAT_SCHEME, qr).await
    } else if qr.starts_with(IDELTACHAT_NOSLASH_SCHEME) {
        decode_ideltachat(context, IDELTACHAT_NOSLASH_SCHEME, qr).await
    } else if qr.starts_with(DCLOGIN_SCHEME) {
        Ok(Qr::Account {
            domain: qr[DCLOGIN_SCHEME.len()..].to_string(),
        })
    } else if starts_with_ignore_case(qr, HTTP_SCHEME) || starts_with_ignore_case(qr, HTTPS_SCHEME) {
        Ok(Qr::Url {
            url: qr.to_string(),
        })
    } else {
        Ok(Qr::Text {
            text: qr.to_string(),
        })
    }
}

