pub(crate) fn create_keypair(addr: EmailAddress, keygen_type: KeyGenType) -> Result<KeyPair> {
    let mut rng = thread_rng();
    let (key_type, bits) = match keygen_type {
        KeyGenType::Default | KeyGenType::Rsa2048 => (PgpKeyType::Rsa, 2048),
        KeyGenType::Rsa4096 => (PgpKeyType::Rsa, 4096),
        KeyGenType::Ed25519 => (PgpKeyType::EdDSA, 0), // Ed25519 doesn't use bits
    };

    let user_id = format!("<{}>", addr);

    // Generate primary key
    let primary_params = SecretKeyParamsBuilder::default()
        .key_type(key_type)
        .can_create_certificates(true)
        .can_sign(true)
        .primary_user_id(user_id)
        .preferred_symmetric_algorithms(vec![SymmetricKeyAlgorithm::AES256])
        .preferred_hash_algorithms(vec![HashAlgorithm::SHA2_256])
        .preferred_compression_algorithms(vec![CompressionAlgorithm::ZLIB])
        .passphrase(None);

    let primary_params = if key_type == PgpKeyType::Rsa {
        primary_params.key_size(bits)
    } else {
        primary_params
    }.build()?;

    // Generate subkey
    let subkey_params = SubkeyParamsBuilder::default()
        .key_type(key_type)
        .can_encrypt(true)
        .passphrase(None);

    let subkey_params = if key_type == PgpKeyType::Rsa {
        subkey_params.key_size(bits)
    } else {
        subkey_params
    }.build()?;

    // Create the keypair
    let secret_key = SignedSecretKey::new(primary_params, vec![subkey_params], &mut rng)?;
    let public_key = SignedPublicKey::from(&secret_key);

    Ok(KeyPair {
        addr,
        public: public_key,
        secret: secret_key,
    })
}

