    let mut running_state = self.inner.running_state.write().await;

    match *running_state {
        RunningState::Running { .. } => {
            self.emit_event(EventType::Warning(
                "There is already another ongoing process running.".to_string(),
            ));
            bail!("Another ongoing process is already running");
        }
        RunningState::ShallStop { .. } => {
            bail!("Cannot allocate ongoing process while stopping");
        }
        RunningState::Stopped => {
            let (cancel_sender, cancel_receiver) = channel::bounded(1);
