pub async fn send_locations_to_chat(
    context: &Context,
    chat_id: ChatId,
    seconds: i64,
) -> Result<()> {
    ensure!(
        !chat_id.is_special(),
        "Invalid chat_id: {}",
        chat_id.to_u32()
    );
    ensure!(seconds >= 0, "Invalid seconds value: {}", seconds);

    let now = time();
    let is_sending_locations_before =
        is_sending_locations_to_chat(context, Some(chat_id)).await?;

    context
        .sql
        .execute(
            "UPDATE chats SET locations_send_begin=?, locations_send_until=? WHERE id=?",
            (
                if seconds > 0 { now } else { 0 },
                if seconds > 0 { now + seconds } else { 0 },
                chat_id,
            ),
        )
        .await?;

    if seconds > 0 && !is_sending_locations_before {
        let mut msg = Message::new(Viewtype::Text);
        msg.text = msg_location_enabled(context).await;
        msg.param
            .set_int(Param::Cmd, SystemMessage::LocationStreamingEnabled as i32);
        send_msg(context, chat_id, &mut msg).await?;
