        let stock_str = stock_str::msg_location_disabled(context).await;
        add_info_msg(context, chat_id, &stock_str, time()).await?;
    }

    emit_chatlist_item_changed(context, chat_id);

    if seconds > 0 {
        context.interrupt_location().await;
        context
            .scheduler
