pub async fn search_msgs(&self, chat_id: Option<ChatId>, query: &str) -> Result<Vec<MsgId>> {
    let mut success = false;
    let mut ret = Vec::new();

    let real_query = query.trim();
    if real_query.is_empty() {
        success = true;
        return Ok(ret);
    }

    let str_like_in_text = format!("%{}%", real_query);
    let str_like_beg = format!("{}%", real_query);

    let sql = if let Some(chat_id) = chat_id {
        "SELECT m.id AS id \
         FROM msgs m \
         LEFT JOIN contacts ct ON m.from_id=ct.id \
         WHERE m.chat_id=? \
         AND m.hidden=0 \
         AND ct.blocked=0 \
         AND txt LIKE ? \
         ORDER BY m.timestamp,m.id"
    } else {
        "SELECT m.id AS id FROM msgs m \
         LEFT JOIN contacts ct ON m.from_id=ct.id \
         LEFT JOIN chats c ON m.chat_id=c.id \
         WHERE m.chat_id>9 \
         AND m.hidden=0 \
         AND c.blocked!=1 \
         AND ct.blocked=0 \
         AND m.txt LIKE ? \
         ORDER BY m.id DESC LIMIT 1000"
    };

    let params: Vec<rusqlite::types::ToSql> = if let Some(chat_id) = chat_id {
        vec![chat_id.into(), str_like_in_text.into(), str_like_beg.into()]
    } else {
        vec![str_like_in_text.into(), str_like_beg.into()]
    };

    ret = self.inner.sql.query_map(
        sql,
        rusqlite::params_from_iter(params),
        |row| Ok(MsgId(row.get(0)?)),
        |rows| rows.collect::<rusqlite::Result<Vec<_>>>(),
    ).await?;

    success = true;

    if success {
        Ok(ret)
    } else {
        Ok(Vec::new())
    }
}

