    if context.is_self_addr(&addr_normalized).await? {
        return Ok(Some(ContactId::SELF));
    }

    let id = context
        .sql
        .query_get_value(
            "SELECT id FROM contacts \
            WHERE addr=?1 COLLATE NOCASE \
