pub(crate) fn truncate(buf: &str, approx_chars: usize) -> Cow<str> {
    if approx_chars > 0 && buf.len() > approx_chars + DC_ELLIPSIS.len() {
        let mut cursor = Cursor::new(Vec::new());
        let mut truncated = String::from(&buf[..approx_chars]);

        if buf.contains(' ') {
            while let Some(last_char) = truncated.chars().last() {
                if last_char == ' ' || last_char == '\n' {
                    break;
                }
                truncated.pop();
            }
        }

        cursor.write_all(truncated.as_bytes()).unwrap();
        cursor.write_all(DC_ELLIPSIS.as_bytes()).unwrap();

        Cow::Owned(String::from_utf8(cursor.into_inner()).unwrap())
    } else {
        Cow::Borrowed(buf)
    }
}

