pub async fn remove_contact_from_chat(
    context: &Context,
    chat_id: ChatId,
    contact_id: ContactId,
) -> Result<()> {
    if chat_id.is_special() || (contact_id.is_special() && contact_id != ContactId::SELF) {
        bail!("Invalid chat_id or contact_id");
    }

    let chat = Chat::load_from_db(context, chat_id).await?;

    if chat.typ != Chattype::Group {
        bail!("Chat is not a group chat");
    }

    if !chat.is_self_in_chat(context).await? {
        context.emit_event(EventType::ErrorSelfNotInGroup(
            "Cannot remove contact from chat; self not in group.".to_string(),
        ));
        bail!("Self not in group");
    }

    let contact = Contact::get_by_id(context, contact_id).await?;

    if chat.is_promoted() {
        let msg = if contact_id == ContactId::SELF {
            context.set_group_explicitly_left(&chat.grpid).await?;
            Message::new(Viewtype::Text)
                .set_text(stock_str::msg_group_left_local(context, ContactId::SELF).await)
                .set_cmd(SystemMessage::MemberRemovedFromGroup)
        } else {
            Message::new(Viewtype::Text)
                .set_text(stock_str::msg_del_member_local(context, contact.get_addr(), ContactId::SELF).await)
                .set_cmd(SystemMessage::MemberRemovedFromGroup)
                .set(Param::Arg, contact.get_addr())
        };

        let msg_id = chat.send_msg(context, msg).await?;
        context.emit_event(EventType::MsgsChanged {
            chat_id,
            msg_id,
        });
    }

    remove_from_chat_contacts_table(context, chat_id, contact_id).await?;

    context.emit_event(EventType::ChatModified(chat_id));

    Ok(())
}

