fn and(
    &mut self,
    mut lhs: Box<PredicateResult>,
    mut rhs: Box<PredicateResult>,
) -> Result<Box<PredicateResult>> {
    Ok(Box::new(move |batch: RecordBatch| {
        let left_result = lhs(batch.clone())?;

        if left_result.iter().all(|&v| !v) {
            // Equivalent to AlwaysFalse
            Ok(BooleanArray::from(vec![false; batch.num_rows()]))
        } else if left_result.iter().all(|&v| v) {
            // Equivalent to AlwaysTrue for left
            rhs(batch)
        } else {
            let right_result = rhs(batch)?;

            if right_result.iter().all(|&v| v) {
                // Equivalent to AlwaysTrue for right
                Ok(left_result)
            } else {
                // Combine left and right results
                and(&left_result, &right_result)
            }
        }
    }))
}

