pub async fn plan_files(&self) -> Result<FileScanTaskStream> {
    let snapshot = self.snapshot.clone();
    if snapshot.is_none() {
        return Ok(Box::pin(futures::stream::empty()));
    }

    let manifest_evaluators = ManifestEvaluatorCache::new();
    let partition_evaluators = ExpressionEvaluatorCache::new();

    let manifests: Vec<ManifestFile> = snapshot
        .unwrap()
        .manifests(&self.file_io)
        .into_iter()
        .filter(|manifest_file| {
            manifest_evaluators
                .get(
                    manifest_file.partition_spec_id(),
                    &self.bound_filter.as_ref().unwrap(),
                )
                .eval(manifest_file)
                .unwrap_or(false)
        })
        .collect();

    let metrics_evaluator = InclusiveMetricsEvaluator::new(
        self.schema.clone(),
        self.bound_filter.as_ref().unwrap().clone(),
        self.case_sensitive,
        self.include_empty_files,
    );

    let min_data_sequence_number = manifests
        .iter()
        .filter(|m| content_type_is_data(m))
        .map(|m| m.min_sequence_number())
        .min()
        .unwrap_or(0);

    let mut data_entries = Vec::new();
    let mut positional_delete_entries = Vec::new();

    for manifest in manifests {
        if !self.check_sequence_number(min_data_sequence_number, &manifest) {
            continue;
        }

        let partition_evaluator = partition_evaluators.get(
            manifest.partition_spec_id(),
            &self.bound_filter.as_ref().unwrap(),
        );

        let manifest_entries = manifest.entries();
        for entry in manifest_entries {
            let data_file = entry.data_file();
            if partition_evaluator.eval(data_file).unwrap_or(false)
                && metrics_evaluator.eval(data_file).unwrap_or(false)
            {
                match data_file.content_type() {
                    DataContentType::Data => data_entries.push(entry.clone()),
                    DataContentType::PositionDeletes => positional_delete_entries.push(entry.clone()),
                    DataContentType::EqualityDeletes => {
                        return Err(Error::new(
                            ErrorKind::FeatureUnsupported,
                            "PyIceberg does not yet support equality deletes",
                        ));
                    }
                }
            }
        }
    }

    positional_delete_entries.sort_by_key(|entry| entry.data_file().sequence_number());

    let file_scan_tasks = data_entries
        .into_iter()
        .map(|data_entry| {
            FileScanTask::new(
                data_entry.data_file().clone(),
                match_deletes_to_data_file(&data_entry, &positional_delete_entries),
            )
        })
        .collect::<Vec<_>>();

    Ok(Box::pin(futures::stream::iter(file_scan_tasks)))
}

