async fn load_table(&self, table: &TableIdent) -> Result<Table> {
    self.check_identifier_is_valid(table)?;

    let mut metadata_type = None;
    let mut response;
    let mut loaded_ident;

    match self.load_internal(table, self.snapshot_mode).await {
        Ok(resp) => {
            response = resp;
            loaded_ident = table.clone();
        }
        Err(original_error) => {
            if let Some(meta_type) = MetadataTableType::from(&table.name) {
                metadata_type = Some(meta_type);
                let base_ident = TableIdent::new(table.namespace.clone(), table.name.clone());
                match self.load_internal(&base_ident, self.snapshot_mode).await {
                    Ok(resp) => {
                        response = resp;
                        loaded_ident = base_ident;
                    }
                    Err(_) => return Err(original_error),
                }
            } else {
                return Err(original_error);
            }
        }
    }

    let final_identifier = loaded_ident;
    let session = self.table_session(&response.config, &self.session(context));
    let table_metadata;

    if self.snapshot_mode == SnapshotMode::Refs {
        let mut builder = TableMetadataBuilder::from(response.table_metadata());
        builder
            .with_metadata_location(response.metadata_location())
            .set_previous_file_location(None)
            .set_snapshots_supplier(Box::new(move || {
                Box::pin(async move {
                    self.load_internal(&final_identifier, SnapshotMode::All)
                        .await?
                        .table_metadata()
                        .snapshots()
                        .cloned()
                        .collect()
                })
            }))
            .discard_changes();
        table_metadata = builder.build()?;
    } else {
        table_metadata = response.table_metadata().clone();
    }

    let ops = RESTTableOperations::new(
        self.client.clone(),
        self.paths.table(&final_identifier),
        Box::new(move || session.headers()),
        self.table_file_io(context, &response.config),
        table_metadata.clone(),
    );

    self.track_file_io(&ops);

    let table = Table::builder()
        .file_io(self.file_io())
        .metadata_location(get_metadata_location(&table_metadata.properties())?)
        .metadata(table_metadata)
        .identifier(final_identifier.clone())
        .build()?;

    if let Some(meta_type) = metadata_type {
        Ok(MetadataTableUtils::create_metadata_table_instance(table, meta_type)?)
    } else {
        Ok(table)
    }
}

