    if format_version.0 < self.table.metadata().format_version.0 {
        return Err(Error::new(
            ErrorKind::DataInvalid,
            format!(
                "Cannot downgrade v{} table to v{}",
                self.table.metadata().format_version.0,
                format_version.0
            ),
        ));
