fn starts_with(
    &mut self,
    reference: &BoundReference,
    datum: &Datum,
    _predicate: &BoundPredicate,
) -> crate::Result<bool> {
    let field_id = reference.field().id;

    if self.contains_nulls_only(field_id) {
        return ROWS_CANNOT_MATCH;
    }

    let lower_bound = match self.lower_bound(field_id) {
        Some(bound) => bound,
        None => return ROWS_CANNOT_MATCH,
    };

    let upper_bound = match self.upper_bound(field_id) {
        Some(bound) => bound,
        None => return ROWS_CANNOT_MATCH,
    };

    let prefix = match datum {
        Datum::Primitive(PrimitiveLiteral::Binary(bytes)) => bytes,
        Datum::Primitive(PrimitiveLiteral::String(s)) => s.as_bytes(),
        _ => return Err(Error::new(ErrorKind::DataInvalid, "Invalid datum type for starts_with")),
    };

    let lower_bytes = match lower_bound {
        Datum::Primitive(PrimitiveLiteral::Binary(bytes)) => bytes,
        Datum::Primitive(PrimitiveLiteral::String(s)) => s.as_bytes(),
        _ => return Err(Error::new(ErrorKind::DataInvalid, "Invalid lower bound type")),
    };

    let upper_bytes = match upper_bound {
        Datum::Primitive(PrimitiveLiteral::Binary(bytes)) => bytes,
        Datum::Primitive(PrimitiveLiteral::String(s)) => s.as_bytes(),
        _ => return Err(Error::new(ErrorKind::DataInvalid, "Invalid upper bound type")),
    };

    let lower_length = std::cmp::min(prefix.len(), lower_bytes.len());
    let upper_length = std::cmp::min(prefix.len(), upper_bytes.len());

    if lower_bytes[..lower_length] > prefix[..lower_length] {
        return ROWS_CANNOT_MATCH;
    }

    if upper_bytes[..upper_length] < prefix[..upper_length] {
        return ROWS_CANNOT_MATCH;
    }

    ROWS_MIGHT_MATCH
}

