fn not_starts_with(
    &mut self,
    reference: &BoundReference,
    datum: &Datum,
    _predicate: &BoundPredicate,
) -> crate::Result<bool> {
    let field_id = reference.field().id;

    if self.contains_nulls_only(field_id) {
        return ROWS_MIGHT_MATCH;
    }

    let prefix = match datum {
        Datum::Primitive(PrimitiveLiteral::Binary(bytes)) => bytes,
        Datum::Primitive(PrimitiveLiteral::String(s)) => s.as_bytes(),
        _ => return Err(Error::new(ErrorKind::DataInvalid, "Invalid datum type for not_starts_with")),
    };

    if let (Some(lower), Some(upper)) = (self.lower_bound(field_id), self.upper_bound(field_id)) {
        let lower_bytes = match lower {
            Datum::Primitive(PrimitiveLiteral::Binary(bytes)) => bytes,
            Datum::Primitive(PrimitiveLiteral::String(s)) => s.as_bytes(),
            _ => return Err(Error::new(ErrorKind::DataInvalid, "Invalid lower bound type")),
        };

        if lower_bytes.len() < prefix.len() {
            return ROWS_MIGHT_MATCH;
        }

        if lower_bytes.starts_with(prefix) {
            let upper_bytes = match upper {
                Datum::Primitive(PrimitiveLiteral::Binary(bytes)) => bytes,
                Datum::Primitive(PrimitiveLiteral::String(s)) => s.as_bytes(),
                _ => return Err(Error::new(ErrorKind::DataInvalid, "Invalid upper bound type")),
            };

            if upper_bytes.len() < prefix.len() {
                return ROWS_MIGHT_MATCH;
            }

            if upper_bytes.starts_with(prefix) {
                return ROWS_CANNOT_MATCH;
            }
        }
    }

    ROWS_MIGHT_MATCH
}

