pub fn kangaroo(e: &[u8], f: &[u8]) -> isize {
    let ge = FP12::from_bytes(e);
    let gf = FP12::from_bytes(f);
    let mut distance = [0; TS];
    let mut t = gf.clone();
    let mut table = vec![FP12::new(); TS];

    let mut s = 1;
    for m in 0..TS {
        distance[m] = s;
        table[m] = t.clone();
        s *= 2;
        t.usqr();
    }

    t.one();
    let mut dn = 0;
    for _ in 0..TRAP {
        let i = t.geta().geta().geta().lastbits(20) as usize % TS;
        t.mul(&table[i]);
        dn += distance[i];
    }

    let mut gf = t.clone();
    gf.conj();
    let mut steps = 0;
    let mut dm = 0;
    let mut res = 0;
    let mut ge = ge;

    while dm - dn < MAXPIN {
        steps += 1;
        if steps > 4 * TRAP {
            break;
        }
        let i = ge.geta().geta().geta().lastbits(20) as usize % TS;
        ge.mul(&table[i]);
        dm += distance[i];
        if ge.equals(&t) {
            res = dm - dn;
            break;
        }
        if ge.equals(&gf) {
            res = dn - dm;
            break;
        }
    }

    if steps > 4 * TRAP || dm - dn >= MAXPIN {
        res = 0; // Trap Failed - probable invalid token
    }

    res
