pub fn is_multi_byte_encoding(name: &str) -> bool {
    let multi_byte_encodings: HashSet<&str> = [
        "utf_8",
        "utf_8_sig",
        "utf_16",
        "utf_16_be",
        "utf_16_le",
        "utf_32",
        "utf_32_le",
        "utf_32_be",
        "utf_7",
    ]
    .iter()
    .cloned()
    .collect();

    multi_byte_encodings.contains(name) || {
        if let Some(encoding) = encoding_from_whatwg_label(name) {
            encoding.is_multi_byte()
        } else {
            false
        }
    }
}

